import React, { createContext, useContext, useState, useEffect } from 'react';
import io from 'socket.io-client';
import axios from 'axios';

const ChatContext = createContext();

export const useChat = () => {
  const context = useContext(ChatContext);
  if (!context) {
    throw new Error('useChat must be used within a ChatProvider');
  }
  return context;
};

export const ChatProvider = ({ children }) => {
  const [socket, setSocket] = useState(null);
  const [mensagens, setMensagens] = useState({});
  const [sessoesAtivas, setSessoesAtivas] = useState([]);
  const [sessaoAtual, setSessaoAtual] = useState(null);

  useEffect(() => {
    // Conectar ao WebSocket quando o componente montar
    const newSocket = io('http://localhost:8001');
    setSocket(newSocket);

    newSocket.on('connect', () => {
      console.log('Conectado ao chat server');
    });

    newSocket.on('nova_mensagem', (data) => {
      setMensagens(prev => ({
        ...prev,
        [data.sessao_id]: [...(prev[data.sessao_id] || []), data]
      }));
    });

    newSocket.on('nova_sessao', (sessao) => {
      setSessoesAtivas(prev => [sessao, ...prev]);
    });

    return () => newSocket.close();
  }, []);

  const iniciarSessao = async (email) => {
    try {
      const response = await axios.post('/api/chat/iniciar', { email });
      const { sessao_id, cliente } = response.data;

      setSessaoAtual({
        id: sessao_id,
        cliente
      });

      // Carregar mensagens existentes
      carregarMensagens(sessao_id);

      return { success: true, sessao_id };
    } catch (error) {
      return { 
        success: false, 
        error: error.response?.data?.detail || 'Erro ao iniciar sessão' 
      };
    }
  };

  const carregarMensagens = async (sessaoId) => {
    try {
      const response = await axios.get(`/api/chat/sessao/${sessaoId}/mensagens`);
      setMensagens(prev => ({
        ...prev,
        [sessaoId]: response.data
      }));
    } catch (error) {
      console.error('Erro ao carregar mensagens:', error);
    }
  };

  const enviarMensagem = async (sessaoId, mensagem) => {
    try {
      await axios.post('/api/chat/mensagem', {
        sessao_id: sessaoId,
        mensagem
      });

      if (socket) {
        socket.emit('mensagem_enviada', {
          sessao_id: sessaoId,
          mensagem,
          remetente: 'cliente'
        });
      }

      return { success: true };
    } catch (error) {
      return { 
        success: false, 
        error: error.response?.data?.detail || 'Erro ao enviar mensagem' 
      };
    }
  };

  const atenderSessao = async (sessaoId) => {
    try {
      await axios.post(`/api/chat/atender/${sessaoId}`);
      setSessaoAtual(sessaoId);
      return { success: true };
    } catch (error) {
      return { 
        success: false, 
        error: error.response?.data?.detail || 'Erro ao atender sessão' 
      };
    }
  };

  const value = {
    socket,
    mensagens,
    sessoesAtivas,
    sessaoAtual,
    setSessaoAtual,
    iniciarSessao,
    enviarMensagem,
    atenderSessao,
    carregarMensagens
  };

  return (
    <ChatContext.Provider value={value}>
      {children}
    </ChatContext.Provider>
  );
};
